/// url = "http://fhir.bih-charite.de/kds-senologie/StructureMap/SenologieToObdsOP"
/// name = "SenologieToObdsOP"
/// title = "Senologie Operation Bundle to oBDS OP-Meldung"
/// status = "draft"

uses "http://hl7.org/fhir/StructureDefinition/Bundle" alias Bundle as source
uses "http://hl7.org/fhir/StructureDefinition/Procedure" alias Procedure as source
uses "http://hl7.org/fhir/StructureDefinition/Condition" alias Condition as source
uses "http://hl7.org/fhir/StructureDefinition/Observation" alias Observation as source
uses "http://hl7.org/fhir/StructureDefinition/Specimen" alias Specimen as source
uses "http://fhir.bih-charite.de/kds-senologie/StructureDefinition/obds-meldung" alias OBDSMeldung as target

imports "http://fhir.bih-charite.de/kds-senologie/StructureMap/SenologieToObdsTumorzuordnung"

// ============================================================================
// Hauptgruppe: Bundle -> oBDS OP-Meldung
// Das Bundle enthaelt eine Procedure (OP), die zugehoerige Condition (Diagnose),
// sowie Observations (pTNM, Histologie) und ggf. Specimen.
// ============================================================================

group SenologieToObdsOP(source src : Bundle, target tgt : OBDSMeldung) {

  // Tumorzuordnung: aus der Condition-Ressource im Bundle
  src.entry as entry where resource.is(Condition) then {
    entry.resource as condition then {
      condition -> tgt.tumorzuordnung as tz then MapTumorzuordnung(condition, tz) "CallMapTumorzuordnung";
    } "ConditionContext";
  } "EntryConditionTZ";

  // OP: aus der Procedure-Ressource im Bundle
  src.entry as entry where resource.is(Procedure) then {
    entry.resource as procedure -> tgt.op as op then MapOP(procedure, op, src) "CallMapOP";
  } "EntryProcedure";
}

// ============================================================================
// OP: Procedure -> OBDSMeldung.op
// Intention, Datum, OPS-Codes
// ============================================================================

group MapOP(source src : Procedure, target tgt : BackboneElement, source bundle : Bundle) {

  // OP_ID: aus Procedure.identifier
  src.identifier as id first then {
    id.value as v -> tgt.opID = v "SetOPID";
  } "MapOPID";

  // Intention: aus Procedure.extension[Intention] mit Uebersetzung SNOMED -> oBDS
  src.extension as ext where url = 'https://www.medizininformatik-initiative.de/fhir/ext/modul-onko/StructureDefinition/mii-ex-onko-operation-intention' then {
    ext.value as val then {
      val.coding as c where system = 'https://www.medizininformatik-initiative.de/fhir/ext/modul-onko/CodeSystem/mii-cs-onko-intention' then {
        c.code as cd -> tgt.intention = cd "SetIntentionDirect";
      } "ExtractIntentionCode";
      val.coding as c where system = 'http://snomed.info/sct'
        -> tgt.intention = translate(c, 'http://fhir.bih-charite.de/kds-senologie/ConceptMap/cm-sct-to-obds-intention', 'code') "TranslateIntention";
    } "MapIntentionValue";
  } "MapIntention";

  // Datum: aus Procedure.performedDateTime
  src.performed as perf where $this.is(dateTime) -> tgt.datum = perf "SetOPDatum";

  // OPS-Codes: aus Procedure.code.coding (OPS-System, 1..*)
  src.code as code then {
    code.coding as c where system = 'http://fhir.de/CodeSystem/bfarm/ops' -> tgt.opsKodes as ops then {
      c.code as cd -> ops.code = cd "SetOPSCode";
      c.version as v -> ops.version = v "SetOPSVersion";
    } "MapOPSCoding";
  } "MapOPSKodes";

  // Histologie: aus Observation im Bundle (postoperativ)
  bundle.entry as histEntry where resource.is(Observation) and resource.code.coding.exists(code = '59847-4') then {
    histEntry.resource as histObs -> tgt.histologie as histo then MapHistologie(histObs, histo) "CallMapHistologie";
  } "EntryHistologie";

  // pTNM: aus TNM-Observation im Bundle (pathologisches Staging)
  // LOINC 21902-2 = "Stage group.pathology Cancer"
  bundle.entry as tnmEntry where resource.is(Observation) and resource.code.coding.exists(code = '21902-2') then {
    tnmEntry.resource as tnmObs -> tgt.tnm as ptnm then MapPTNM(tnmObs, ptnm) "CallMapPTNM";
  } "EntryPTNM";

  // Residualstatus: aus Procedure.outcome oder separater Observation
  src.outcome as outcome then MapResidualstatus(outcome, tgt) "CallMapResidualstatus";

  // Komplikationen: aus Procedure.complication
  src -> tgt.komplikationen as komp then MapKomplikationen(src, komp) "CallMapKomplikationen";

  // Operateure: aus Procedure.performer
  src.performer as perf -> tgt.operateure as op then MapOperateur(perf, op) "CallMapOperateur";

  // Modul_Mamma: Hormonrezeptoren + HER2 aus Observations im Bundle
  src -> tgt.modulMamma as mamma then MapModulMammaOP(bundle, mamma) "CallMapModulMammaOP";
}

// ============================================================================
// Histologie: Observation -> OBDSMeldung.op.histologie
// Postoperativer Histologiebefund mit Morphologie, Grading, Lymphknoten
// ============================================================================

group MapHistologie(source src : Observation, target tgt : BackboneElement) {

  // Histologie_ID
  src.identifier as id first then {
    id.value as v -> tgt.histologieID = v "SetHistologieID";
  } "MapHistologieID";

  // Tumor_Histologiedatum
  src.effective as eff where $this.is(dateTime) -> tgt.tumorHistologiedatum = eff "SetHistologiedatum";

  // Histologie_EinsendeNr
  src.identifier as id where system = 'http://pathologie.charite.de/fhir/sid/einsende-nr' then {
    id.value as v -> tgt.histologieEinsendeNr = v "SetEinsendeNr";
  } "MapEinsendeNr";

  // Morphologie_ICD_O
  src.value as val then {
    val.coding as c where system = 'urn:oid:2.16.840.1.113883.6.43.1' -> tgt.morphologieICDO as morph then {
      c.code as cd -> morph.code = cd "SetMorphCode";
      c.version as v -> morph.version = v "SetMorphVersion";
    } "MapMorphCoding";
  } "MapMorphologie";

  // Morphologie_Freitext
  src.value as val then {
    val.text as t -> tgt.morphologieFreitext = t "SetMorphFreitext";
  } "MapMorphFreitext";

  // Grading: Uebersetzung SNOMED -> oBDS
  src.component as comp where code.coding.exists(code = '59542-1') then {
    comp.value as val then {
      val.coding as c -> tgt.grading = translate(c, 'http://fhir.bih-charite.de/kds-senologie/ConceptMap/cm-sct-to-obds-grading', 'code') "TranslateGrading";
    } "MapGradingValue";
  } "MapGrading";

  // LK_untersucht: Anzahl untersuchter Lymphknoten
  src.component as comp where code.coding.exists(code = '21894-1') then {
    comp.value as val -> tgt.lkUntersucht = val "SetLKUntersucht";
  } "MapLKUntersucht";

  // LK_befallen: Anzahl befallener Lymphknoten
  src.component as comp where code.coding.exists(code = '21893-3') then {
    comp.value as val -> tgt.lkBefallen = val "SetLKBefallen";
  } "MapLKBefallen";

  // Sentinel_LK_untersucht
  src.component as comp where code.coding.exists(code = '92832-5') then {
    comp.value as val -> tgt.sentinelLKUntersucht = val "SetSentinelLKUntersucht";
  } "MapSentinelLKUntersucht";

  // Sentinel_LK_befallen
  src.component as comp where code.coding.exists(code = '92831-7') then {
    comp.value as val -> tgt.sentinelLKBefallen = val "SetSentinelLKBefallen";
  } "MapSentinelLKBefallen";
}

// ============================================================================
// pTNM: Observation -> OBDSMeldung.op.tnm
// Pathologisches TNM-Staging mit p-Praefix, m_Symbol, UICC
// LOINC 21902-2 = "Stage group.pathology Cancer"
// ============================================================================

group MapPTNM(source src : Observation, target tgt : BackboneElement) {

  // Datum der TNM-Klassifikation
  src.effective as eff where $this.is(dateTime) -> tgt.datum = eff "SetTNMDatum";

  // TNM-Auflage (Version)
  src.method as method then {
    method.coding as c then {
      c.code as cd -> tgt.version = cd "SetTNMVersion";
    } "ExtractTNMVersionCode";
  } "MapTNMVersion";

  // y-Symbol
  src.component as comp where code.coding.exists(code = '59479-6') then {
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.ySymbol = cd "SetYSymbol";
      } "ExtractYCode";
    } "MapYValue";
  } "MapYSymbol";

  // r-Symbol
  src.component as comp where code.coding.exists(code = '21983-2') then {
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.rSymbol = cd "SetRSymbol";
      } "ExtractRCode";
    } "MapRValue";
  } "MapRSymbol";

  // a-Symbol
  src.component as comp where code.coding.exists(code = '101659-7') then {
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.aSymbol = cd "SetASymbol";
      } "ExtractACode";
    } "MapAValue";
  } "MapASymbol";

  // T-Kategorie (pathologisch -> Praefix p)
  // LOINC 21899-0 = "Primary tumor.pathology Cancer"
  src.component as comp where code.coding.exists(code = '21899-0') then {
    comp -> tgt.cpuPraefixT = 'p' "SetPPrefixT";
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.t = cd "SetT";
      } "ExtractTCode";
    } "MapTValue";
  } "MapT";

  // m_Symbol: multiple Primaertumoren
  src.component as comp where code.coding.exists(code = '42030-7') then {
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.mSymbol = cd "SetMSymbol";
      } "ExtractMSymbolCode";
    } "MapMSymbolValue";
  } "MapMSymbol";

  // N-Kategorie (pathologisch -> Praefix p)
  // LOINC 21900-6 = "Regional lymph nodes.pathology Cancer"
  src.component as comp where code.coding.exists(code = '21900-6') then {
    comp -> tgt.cpuPraefixN = 'p' "SetPPrefixN";
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.n = cd "SetN";
      } "ExtractNCode";
    } "MapNValue";
  } "MapN";

  // M-Kategorie (kann klinisch oder pathologisch sein)
  // LOINC 21901-4 = "Distant metastases.pathology Cancer"
  src.component as comp where code.coding.exists(code = '21901-4') then {
    comp -> tgt.cpuPraefixM = 'p' "SetPPrefixM";
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.m = cd "SetM";
      } "ExtractMCode";
    } "MapMValue";
  } "MapMPath";

  // M-Kategorie (klinisch, falls keine pathologische vorhanden)
  // LOINC 21907-1 = "Distant metastases.clinical Cancer"
  src.component as comp where code.coding.exists(code = '21907-1') then {
    comp -> tgt.cpuPraefixM = 'c' "SetCPrefixM";
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.m = cd "SetMClinical";
      } "ExtractMClinCode";
    } "MapMClinValue";
  } "MapMClin";

  // L: Lymphgefaessinvasion
  src.component as comp where code.coding.exists(code = '33739-4') then {
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.l = cd "SetL";
      } "ExtractLCode";
    } "MapLValue";
  } "MapL";

  // V: Veneninvasion
  src.component as comp where code.coding.exists(code = '33740-2') then {
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.v = cd "SetV";
      } "ExtractVCode";
    } "MapVValue";
  } "MapV";

  // Pn: Perineurale Invasion
  src.component as comp where code.coding.exists(code = '92837-4') then {
    comp.value as val then {
      val.coding as c then {
        c.code as cd -> tgt.pn = cd "SetPn";
      } "ExtractPnCode";
    } "MapPnValue";
  } "MapPn";

  // UICC-Stadium
  src.value as val then {
    val.coding as c then {
      c.code as cd -> tgt.uiccStadium = cd "SetUICC";
    } "ExtractUICC";
  } "MapUICC";
}

// ============================================================================
// Residualstatus: Procedure.outcome -> OBDSMeldung.op.residualstatus
// R-Klassifikation (R0, R1, R2, RX) aus dem Outcome-CodeableConcept
// ============================================================================

group MapResidualstatus(source src : CodeableConcept, target tgt : BackboneElement) {

  // Lokale Beurteilung: direkte oBDS-Codes aus Outcome
  src.coding as c where system = 'https://www.medizininformatik-initiative.de/fhir/ext/modul-onko/CodeSystem/mii-cs-onko-residualstatus' -> tgt.residualstatus as rs then {
    c.code as cd -> rs.lokaleBeurteilung = cd "SetLokaleBeurteilung";
    c.code as cd -> rs.gesamtbeurteilung = cd "SetGesamtbeurteilung";
  } "MapResidualDirect";

  // Uebersetzung SNOMED -> oBDS Residualstatus
  src.coding as c where system = 'http://snomed.info/sct' -> tgt.residualstatus as rs then {
    c -> rs.lokaleBeurteilung = translate(c, 'http://fhir.bih-charite.de/kds-senologie/ConceptMap/cm-sct-to-obds-residualstatus', 'code') "TranslateLokaleBeurteilung";
    c -> rs.gesamtbeurteilung = translate(c, 'http://fhir.bih-charite.de/kds-senologie/ConceptMap/cm-sct-to-obds-residualstatus', 'code') "TranslateGesamtbeurteilung";
  } "MapResidualSNOMED";
}

// ============================================================================
// Komplikationen: Procedure -> OBDSMeldung.op.komplikationen
// Komplikationskuerzel (oBDS) und ICD-10-kodierte Komplikationen
// ============================================================================

group MapKomplikationen(source src : Procedure, target tgt : BackboneElement) {

  // Keine Komplikation: wenn complication leer ist
  src where complication.exists().not() -> tgt.komplikationNeinOderUnbekannt = 'N' "SetKeineKomplikation";

  // Komplikationen vorhanden: oBDS-Kuerzel aus complication[compl_obds]
  src.complication as comp then {
    comp.coding as c where system = 'https://www.medizininformatik-initiative.de/fhir/ext/modul-onko/CodeSystem/mii-cs-onko-operation-komplikation' -> tgt.komplikation as k then {
      c.code as cd -> k.kuerzel = cd "SetKomplikationKuerzel";
    } "MapKomplikationObds";
  } "MapKomplikationenObds";

  // Komplikationen mit ICD-10-Kodierung aus complication[compl_icd10]
  src.complication as comp then {
    comp.coding as c where system = 'http://fhir.de/CodeSystem/bfarm/icd-10-gm' -> tgt.komplikation as k then {
      c -> k.icd as icd then {
        c.code as cd -> icd.code = cd "SetKompIcdCode";
        c.version as v -> icd.version = v "SetKompIcdVersion";
      } "MapKompIcd";
    } "MapKomplikationIcd";
  } "MapKomplikationenIcd";
}

// ============================================================================
// Operateur: Procedure.performer -> OBDSMeldung.op.operateure
// Nachname, Vornamen, Hauptoperateur-Kennzeichen
// ============================================================================

group MapOperateur(source src : BackboneElement, target tgt : BackboneElement) {

  // Operateur-Daten aus Procedure.performer.actor (Reference -> Practitioner)
  // Nachname + Vornamen aus actor.display (Format: "Nachname, Vornamen")
  src.actor as actor then {
    actor.display as d -> tgt.nachname = d "SetOperateurName";
  } "MapOperateurName";

  // Hauptoperateur: aus Procedure.performer.function
  src.function as func then {
    func.coding as c where code = 'primary' -> tgt.hauptoperateur = 'J' "SetHauptoperateurJa";
    func.coding as c where code = 'secondary' -> tgt.hauptoperateur = 'N' "SetHauptoperateurNein";
  } "MapHauptoperateur";

  // Fallback: wenn keine function angegeben, erster Performer = Hauptoperateur
  src where function.exists().not() -> tgt.hauptoperateur = 'J' "SetHauptoperateurDefault";
}

// ============================================================================
// Modul_Mamma (OP): Hormonrezeptoren + HER2 aus postoperativen Observations
// Gleiche Struktur wie bei Diagnose, aber aus dem OP-Bundle
// ============================================================================

group MapModulMammaOP(source src : Bundle, target tgt : BackboneElement) {

  // Oestrogenrezeptor (LOINC 85337-4)
  src.entry as erEntry where resource.is(Observation) and resource.code.coding.exists(code = '85337-4') then {
    erEntry.resource as erObs then {
      erObs.value as val then {
        val.coding as c where code = '10828004' -> tgt.hormonrezeptorStatusOestrogen = 'P' "SetERPositiv";
        val.coding as c where code = '260385009' -> tgt.hormonrezeptorStatusOestrogen = 'N' "SetERNegativ";
      } "MapERValue";
    } "MapERObs";
  } "EntryER";

  // Progesteronrezeptor (LOINC 85339-0)
  src.entry as prEntry where resource.is(Observation) and resource.code.coding.exists(code = '85339-0') then {
    prEntry.resource as prObs then {
      prObs.value as val then {
        val.coding as c where code = '10828004' -> tgt.hormonrezeptorStatusProgesteron = 'P' "SetPRPositiv";
        val.coding as c where code = '260385009' -> tgt.hormonrezeptorStatusProgesteron = 'N' "SetPRNegativ";
      } "MapPRValue";
    } "MapPRObs";
  } "EntryPR";

  // HER2-Status (LOINC 85319-2)
  src.entry as herEntry where resource.is(Observation) and resource.code.coding.exists(code = '85319-2') then {
    herEntry.resource as herObs then {
      herObs.value as val then {
        val.coding as c where code = '10828004' -> tgt.her2neuStatus = 'P' "SetHER2Positiv";
        val.coding as c where code = '260385009' -> tgt.her2neuStatus = 'N' "SetHER2Negativ";
      } "MapHER2Value";
    } "MapHER2Obs";
  } "EntryHER2";
}
